    /**
     * @method
     * @name backpack#fetchCurrencies
     * @description fetches all available currencies on an exchange
     * @see https://docs.backpack.exchange/#tag/Assets
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} an associative dictionary of currencies
     */
    public java.util.concurrent.CompletableFuture<Object> fetchCurrencies(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            Object response = (this.publicGetApiV1Assets(parameters)).join();
            //
            //     [
            //         {
            //             "coingeckoId": "jito-governance-token",
            //             "displayName": "Jito",
            //             "symbol": "JTO",
            //             "tokens": [
            //                 {
            //                     "blockchain": "Solana",
            //                     "contractAddress": "jtojtomepa8beP8AuQc6eXt5FriJwfFMwQx2v2f9mCL",
            //                     "depositEnabled": true,
            //                     "displayName": "Jito",
            //                     "maximumWithdrawal": null,
            //                     "minimumDeposit": "0.28",
            //                     "minimumWithdrawal": "0.58",
            //                     "withdrawEnabled": true,
            //                     "withdrawalFee": "0.29"
            //                 }
            //             ]
            //         }
            //         ...
            //     ]
            //
            return this.parseCurrencies(response);
        });

    }

    public Object parseCurrency(Object rawCurrency)
    {
        Object currencyId = this.safeString(rawCurrency, "symbol");
        Object code = this.safeCurrencyCode(currencyId);
        Object networks = this.safeList(rawCurrency, "tokens", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
        Object parsedNetworks = new java.util.HashMap<String, Object>() {{}};
        for (var j = 0; Helpers.isLessThan(j, Helpers.getArrayLength(networks)); j++)
        {
            Object network = Helpers.GetValue(networks, j);
            Object networkId = this.safeString(network, "blockchain");
            Object networkIdLowerCase = this.safeStringLower(network, "blockchain");
            Object networkCode = this.networkIdToCode(networkIdLowerCase, code);
            Helpers.addElementToObject(parsedNetworks, networkCode, new java.util.HashMap<String, Object>() {{
    put( "id", networkId );
    put( "network", networkCode );
    put( "limits", new java.util.HashMap<String, Object>() {{
        put( "withdraw", new java.util.HashMap<String, Object>() {{
            put( "min", BackpackCore.this.safeNumber(network, "minimumWithdrawal") );
            put( "max", BackpackCore.this.parseNumber(BackpackCore.this.omitZero(BackpackCore.this.safeString(network, "maximumWithdrawal"))) );
        }} );
        put( "deposit", new java.util.HashMap<String, Object>() {{
            put( "min", BackpackCore.this.safeNumber(network, "minimumDeposit") );
            put( "max", null );
        }} );
    }} );
    put( "active", null );
    put( "deposit", BackpackCore.this.safeBool(network, "depositEnabled") );
    put( "withdraw", BackpackCore.this.safeBool(network, "withdrawEnabled") );
    put( "fee", BackpackCore.this.safeNumber(network, "withdrawalFee") );
    put( "precision", null );
    put( "info", network );
}});
        }
        Object active = null;
        Object deposit = null;
        Object withdraw = null;
        if (Helpers.isTrue(this.isEmpty(parsedNetworks)))
        {
            active = false;
            deposit = false;
            withdraw = false;
        }
        final Object finalActive = active;
        final Object finalDeposit = deposit;
        final Object finalWithdraw = withdraw;
        return this.safeCurrencyStructure(new java.util.HashMap<String, Object>() {{
            put( "id", currencyId );
            put( "code", code );
            put( "precision", null );
            put( "type", "crypto" );
            put( "name", BackpackCore.this.safeString(rawCurrency, "displayName") );
            put( "active", finalActive );
            put( "deposit", finalDeposit );
            put( "withdraw", finalWithdraw );
            put( "fee", null );
            put( "limits", new java.util.HashMap<String, Object>() {{
                put( "deposit", new java.util.HashMap<String, Object>() {{
                    put( "min", null );
                    put( "max", null );
                }} );
                put( "withdraw", new java.util.HashMap<String, Object>() {{
                    put( "min", null );
                    put( "max", null );
                }} );
            }} );
            put( "networks", parsedNetworks );
            put( "info", rawCurrency );
        }});
    }

