    public Object parseMarket(Object market)
    {
        //
        //     [
        //         {
        //             "baseSymbol": "SOL",
        //             "createdAt": "2025-01-21T06:34:54.691858",
        //             "filters": {
        //                 "price": {
        //                     "borrowmarketFeeMaxMultiplier": null,
        //                     "borrowmarketFeeMinMultiplier": null,
        //                     "maxImpactMultiplier": "1.03",
        //                     "maxMultiplier": "1.25",
        //                     "maxPrice": null,
        //                     "meanMarkPriceBand": {
        //                         "maxMultiplier": "1.15",
        //                         "minMultiplier": "0.9"
        //                     },
        //                     "meanPremiumBand": null,
        //                     "minImpactMultiplier": "0.97",
        //                     "minMultiplier": "0.75",
        //                     "minPrice": "0.01",
        //                     "tickSize": "0.01"
        //                 },
        //                 "quantity": {
        //                     "maxQuantity": null,
        //                     "minQuantity": "0.01",
        //                     "stepSize": "0.01"
        //                 }
        //             },
        //             "fundingInterval": 28800000,
        //             "fundingRateLowerBound": null,
        //             "fundingRateUpperBound": null,
        //             "imfFunction": null,
        //             "marketType": "SPOT",
        //             "mmfFunction": null,
        //             "openInterestLimit": "0",
        //             "orderBookState": "Open",
        //             "quoteSymbol": "USDC",
        //             "symbol": "SOL_USDC"
        //         },
        //         {
        //             "baseSymbol": "SOL",
        //             "createdAt": "2025-01-21T06:34:54.691858",
        //             "filters": {
        //                 "price": {
        //                     "borrowEntryFeeMaxMultiplier": null,
        //                     "borrowEntryFeeMinMultiplier": null,
        //                     "maxImpactMultiplier": "1.03",
        //                     "maxMultiplier": "1.25",
        //                     "maxPrice": "1000",
        //                     "meanMarkPriceBand": {
        //                         "maxMultiplier": "1.1",
        //                         "minMultiplier": "0.9"
        //                     },
        //                     "meanPremiumBand": {
        //                         "tolerancePct": "0.05"
        //                     },
        //                     "minImpactMultiplier": "0.97",
        //                     "minMultiplier": "0.75",
        //                     "minPrice": "0.01",
        //                     "tickSize": "0.01"
        //                 },
        //                 "quantity": {
        //                     "maxQuantity": null,
        //                     "minQuantity": "0.01",
        //                     "stepSize": "0.01"
        //                 }
        //             },
        //             "fundingInterval": "28800000",
        //             "fundingRateLowerBound": "-100",
        //             "fundingRateUpperBound": "100",
        //             "imfFunction": {
        //                 "base": "0.02",
        //                 "factor": "0.0001275",
        //                 "type": "sqrt"
        //             },
        //             "marketType": "PERP",
        //             "mmfFunction": {
        //                 "base": "0.0125",
        //                 "factor": "0.0000765",
        //                 "type": "sqrt"
        //             },
        //             "openInterestLimit": "4000000",
        //             "orderBookState": "Open",
        //             "quoteSymbol": "USDC",
        //             "symbol": "SOL_USDC_PERP"
        //         }
        //     ]
        //
        Object id = this.safeString(market, "symbol");
        Object baseId = this.safeString(market, "baseSymbol");
        Object quoteId = this.safeString(market, "quoteSymbol");
        Object base = this.safeCurrencyCode(baseId);
        Object quote = this.safeCurrencyCode(quoteId);
        Object symbol = Helpers.add(Helpers.add(base, "/"), quote);
        Object filters = this.safeDict(market, "filters", new java.util.HashMap<String, Object>() {{}});
        Object priceFilter = this.safeDict(filters, "price", new java.util.HashMap<String, Object>() {{}});
        Object maxPrice = this.safeNumber(priceFilter, "maxPrice");
        Object minPrice = this.safeNumber(priceFilter, "minPrice");
        Object pricePrecision = this.safeNumber(priceFilter, "tickSize");
        Object quantityFilter = this.safeDict(filters, "quantity", new java.util.HashMap<String, Object>() {{}});
        Object maxQuantity = this.safeNumber(quantityFilter, "maxQuantity");
        Object minQuantity = this.safeNumber(quantityFilter, "minQuantity");
        Object amountPrecision = this.safeNumber(quantityFilter, "stepSize");
        Object type = null;
        Object typeOfMarket = this.parseMarketType(this.safeString(market, "marketType"));
        Object linear = null;
        Object inverse = null;
        Object settle = null;
        Object settleId = null;
        Object contractSize = null;
        if (Helpers.isTrue(Helpers.isEqual(typeOfMarket, "spot")))
        {
            type = "spot";
        } else if (Helpers.isTrue(Helpers.isEqual(typeOfMarket, "swap")))
        {
            type = "swap";
            linear = true;
            inverse = false;
            settleId = this.safeString(market, "quoteSymbol");
            settle = this.safeCurrencyCode(settleId);
            symbol = Helpers.add(symbol, Helpers.add(":", settle));
            contractSize = 1;
        }
        Object orderBookState = this.safeString(market, "orderBookState");
        final Object finalSymbol = symbol;
        final Object finalBase = base;
        final Object finalSettle = settle;
        final Object finalSettleId = settleId;
        final Object finalType = type;
        final Object finalOrderBookState = orderBookState;
        final Object finalLinear = linear;
        final Object finalInverse = inverse;
        final Object finalContractSize = contractSize;
        return this.safeMarketStructure(new java.util.HashMap<String, Object>() {{
            put( "id", id );
            put( "symbol", finalSymbol );
            put( "base", finalBase );
            put( "quote", quote );
            put( "settle", finalSettle );
            put( "baseId", baseId );
            put( "quoteId", quoteId );
            put( "settleId", finalSettleId );
            put( "type", finalType );
            put( "spot", Helpers.isEqual(finalType, "spot") );
            put( "margin", Helpers.isEqual(finalType, "spot") );
            put( "swap", Helpers.isEqual(finalType, "swap") );
            put( "future", false );
            put( "option", false );
            put( "active", Helpers.isEqual(finalOrderBookState, "Open") );
            put( "contract", !Helpers.isEqual(finalType, "spot") );
            put( "linear", finalLinear );
            put( "inverse", finalInverse );
            put( "taker", null );
            put( "maker", null );
            put( "contractSize", finalContractSize );
            put( "expiry", null );
            put( "expiryDatetime", null );
            put( "strike", null );
            put( "optionType", null );
            put( "precision", new java.util.HashMap<String, Object>() {{
                put( "amount", amountPrecision );
                put( "price", pricePrecision );
            }} );
            put( "limits", new java.util.HashMap<String, Object>() {{
                put( "leverage", new java.util.HashMap<String, Object>() {{
                    put( "min", null );
                    put( "max", null );
                }} );
                put( "amount", new java.util.HashMap<String, Object>() {{
                    put( "min", minQuantity );
                    put( "max", maxQuantity );
                }} );
                put( "price", new java.util.HashMap<String, Object>() {{
                    put( "min", minPrice );
                    put( "max", maxPrice );
                }} );
                put( "cost", new java.util.HashMap<String, Object>() {{
                    put( "min", null );
                    put( "max", null );
                }} );
            }} );
            put( "created", BackpackCore.this.parse8601(BackpackCore.this.safeString(market, "createdAt")) );
            put( "info", market );
        }});
    }

    public Object parseMarketType(Object type)
    {
        Object types = new java.util.HashMap<String, Object>() {{
            put( "SPOT", "spot" );
            put( "PERP", "swap" );
        }};
        return this.safeString(types, type, type);
    }

