    public Object parseTrade(Object trade, Object... optionalArgs)
    {
        //
        // fetchTrades
        //     {
        //         "id": 8721563,
        //         "isBuyerMaker": false,
        //         "price": "117427.6",
        //         "quantity": "0.00016",
        //         "quoteQuantity": "18.788416",
        //         "timestamp": 1753123916819
        //     }
        //
        // fetchMyTrades
        //     {
        //         "clientId": null,
        //         "fee": "0.004974",
        //         "feeSymbol": "USDC",
        //         "isMaker": false,
        //         "orderId": "4238907375",
        //         "price": "3826.15",
        //         "quantity": "0.0026",
        //         "side": "Bid",
        //         "symbol": "ETH_USDC_PERP",
        //         "systemOrderType": null,
        //         "timestamp": "2025-07-27T17:39:00.092",
        //         "tradeId": 9748827
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object id = this.safeString2(trade, "id", "tradeId");
        Object marketId = this.safeString(trade, "symbol");
        market = this.safeMarket(marketId, market);
        Object price = this.safeString(trade, "price");
        Object amount = this.safeString(trade, "quantity");
        Object isBuyerMaker = this.safeBool(trade, "isBuyerMaker");
        Object side = this.parseOrderSide(this.safeString(trade, "side"));
        Object isMaker = this.safeBool(trade, "isMaker");
        Object takerOrMaker = null;
        if (Helpers.isTrue(!Helpers.isEqual(isMaker, null)))
        {
            takerOrMaker = ((Helpers.isTrue(isMaker))) ? "maker" : "taker";
        } else if (Helpers.isTrue(!Helpers.isEqual(isBuyerMaker, null)))
        {
            takerOrMaker = "taker";
            side = ((Helpers.isTrue(isBuyerMaker))) ? "sell" : "buy";
        }
        Object orderId = this.safeString(trade, "orderId");
        Object fee = null;
        Object feeAmount = this.safeString(trade, "fee");
        Object timestamp = this.safeInteger(trade, "timestamp");
        if (Helpers.isTrue(!Helpers.isEqual(feeAmount, null)))
        {
            // if fetchMyTrades
            Object datetime = this.safeString(trade, "timestamp");
            timestamp = this.parse8601(datetime);
        }
        Object feeSymbol = this.safeCurrencyCode(this.safeString(trade, "feeSymbol"));
        if (Helpers.isTrue(!Helpers.isEqual(feeAmount, null)))
        {
            final Object finalFeeAmount = feeAmount;
            fee = new java.util.HashMap<String, Object>() {{
                put( "cost", finalFeeAmount );
                put( "currency", feeSymbol );
                put( "rate", null );
            }};
        }
        final Object finalTimestamp = timestamp;
        final Object finalMarket = market;
        final Object finalSide = side;
        final Object finalTakerOrMaker = takerOrMaker;
        final Object finalFee = fee;
        return this.safeTrade(new java.util.HashMap<String, Object>() {{
            put( "info", trade );
            put( "timestamp", finalTimestamp );
            put( "datetime", BackpackCore.this.iso8601(finalTimestamp) );
            put( "symbol", Helpers.GetValue(finalMarket, "symbol") );
            put( "id", id );
            put( "order", orderId );
            put( "type", null );
            put( "side", finalSide );
            put( "takerOrMaker", finalTakerOrMaker );
            put( "price", price );
            put( "amount", amount );
            put( "cost", null );
            put( "fee", finalFee );
        }}, market);
    }

