    public Object parseTransaction(Object transaction, Object... optionalArgs)
    {
        //
        // fetchDeposits
        //     [
        //         {
        //             "createdAt": "2025-07-23T13:55:54.267",
        //             "fiatAmount": null,
        //             "fiatCurrency": null,
        //             "fromAddress": "0x2e3ab3e88a7dbdc763aadf5b28c18fb085af420a",
        //             "id": 6695353,
        //             "institutionBic": null,
        //             "platformMemo": null,
        //             "quantity": "120",
        //             "source": "ethereum",
        //             "status": "confirmed",
        //             "symbol": "USDC",
        //             "toAddress": "0xfBe7CbfCde93c8a4204a4be6B56732Eb32690170",
        //             "transactionHash": "0x58edaac415398d617b34c6673fffcaf0024990d5700565030119db5cbf3765d1"
        //         }
        //     ]
        //
        // withdraw
        //     {
        //         "accountIdentifier": null,
        //         "bankIdentifier": null,
        //         "bankName": null,
        //         "blockchain": "Ethereum",
        //         "clientId": null,
        //         "createdAt": "2025-08-13T19:27:13.817",
        //         "fee": "3",
        //         "fiatFee": null,
        //         "fiatState": null,
        //         "fiatSymbol": null,
        //         "id": 5479929,
        //         "identifier": null,
        //         "isInternal": false,
        //         "providerId": null,
        //         "quantity": "10",
        //         "status": "pending",
        //         "subaccountId": null,
        //         "symbol": "USDC",
        //         "toAddress": "0x0ad42b8e602c2d3d475ae52d678cf63d84ab2749",
        //         "transactionHash": null,
        //         "triggerAt": null
        //     }
        //
        // fetchWithdrawals
        //     [
        //         {
        //             "accountIdentifier": null,
        //             "bankIdentifier": null,
        //             "bankName": null,
        //             "blockchain": "Ethereum",
        //             "clientId": null,
        //             "createdAt": "2025-08-13T19:27:13.817",
        //             "fee": "3",
        //             "fiatFee": null,
        //             "fiatState": null,
        //             "fiatSymbol": null,
        //             "id": 5479929,
        //             "identifier": null,
        //             "isInternal": false,
        //             "providerId": null,
        //             "quantity": "10",
        //             "status": "confirmed",
        //             "subaccountId": null,
        //             "symbol": "USDC",
        //             "toAddress": "0x0ad42b8e602c2d3d475ae52d678cf63d84ab2749",
        //             "transactionHash": "0x658b6d082af4afa0d3cf85caf344ff7c19d980117726bf193b00d8850f8746a1",
        //             "triggerAt": null
        //         }
        //     ]
        //
        Object currency = Helpers.getArg(optionalArgs, 0, null);
        Object status = this.parseTransactionStatus(this.safeString(transaction, "status"));
        Object id = this.safeString(transaction, "id");
        Object txid = this.safeString(transaction, "transactionHash");
        Object coin = this.safeString(transaction, "symbol");
        Object code = this.safeCurrencyCode(coin, currency);
        Object timestamp = this.parse8601(this.safeString(transaction, "createdAt"));
        Object amount = this.safeNumber(transaction, "quantity");
        Object networkId = this.safeStringLower2(transaction, "source", "blockchain");
        Object network = this.networkIdToCode(networkId, code);
        Object addressTo = this.safeString(transaction, "toAddress");
        Object addressFrom = this.safeString(transaction, "fromAddress");
        Object tag = this.safeString(transaction, "platformMemo");
        Object feeCost = this.safeNumber(transaction, "fee");
        Object intern = this.safeBool(transaction, "isInternal", false);
        Object fee = null;
        if (Helpers.isTrue(!Helpers.isEqual(feeCost, null)))
        {
            final Object finalFeeCost = feeCost;
            fee = new java.util.HashMap<String, Object>() {{
                put( "cost", finalFeeCost );
                put( "currency", code );
            }};
        }
        final Object finalFee = fee;
        return new java.util.HashMap<String, Object>() {{
            put( "info", transaction );
            put( "id", id );
            put( "txid", txid );
            put( "timestamp", timestamp );
            put( "datetime", BackpackCore.this.iso8601(timestamp) );
            put( "network", network );
            put( "address", null );
            put( "addressTo", addressTo );
            put( "addressFrom", addressFrom );
            put( "tag", tag );
            put( "tagTo", null );
            put( "tagFrom", null );
            put( "type", null );
            put( "amount", amount );
            put( "currency", code );
            put( "status", status );
            put( "updated", null );
            put( "internal", intern );
            put( "comment", null );
            put( "fee", finalFee );
        }};
    }

